import{_ as e,o as r,c as a,a2 as l}from"./chunks/framework.DjxoKHTk.js";const b=JSON.parse('{"title":"眷村涼麵 — 老一輩傳下來的秘方","description":"媽媽示範傳統眷村涼麵，不放花生醬、純用芝麻醬，加甜酒釀和花椒油，充滿時代記憶的經典靈魂涼麵。","frontmatter":{"title":"眷村涼麵 — 老一輩傳下來的秘方","description":"媽媽示範傳統眷村涼麵，不放花生醬、純用芝麻醬，加甜酒釀和花椒油，充滿時代記憶的經典靈魂涼麵。"},"headers":[],"relativePath":"中式/眷村涼麵.md","filePath":"中式/眷村涼麵.md","lastUpdated":1781138667000}'),d={name:"中式/眷村涼麵.md"};function n(i,t,o,s,h,c){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="眷村涼麵-—-老一輩傳下來的秘方" tabindex="-1">眷村涼麵 — 老一輩傳下來的秘方 <a class="header-anchor" href="#眷村涼麵-—-老一輩傳下來的秘方" aria-label="Permalink to &quot;眷村涼麵 — 老一輩傳下來的秘方&quot;">​</a></h1><blockquote><p><strong>來源</strong>: <a href="https://youtu.be/4jiowGDwbr4" target="_blank" rel="noreferrer">YouTube - 媽媽的傳承 Anne and Julie</a><strong>頻道</strong>: 媽媽的傳承 Anne and Julie <strong>分享日期</strong>: 2026/06/08 <strong>分類</strong>: 中式/台式</p></blockquote><hr><h2 id="影片特色" tabindex="-1">影片特色 <a class="header-anchor" href="#影片特色" aria-label="Permalink to &quot;影片特色&quot;">​</a></h2><blockquote><p>媽媽示範早期眷村涼麵的完整做法，強調<strong>不放花生醬、純用芝麻醬</strong>的傳統版本。多加了「甜酒釀」和「花椒油」，讓醬汁濃郁度與層次感瞬間爆發，充滿時代記憶的經典靈魂涼麵。</p></blockquote><hr><h2 id="📝-食材" tabindex="-1">📝 食材 <a class="header-anchor" href="#📝-食材" aria-label="Permalink to &quot;📝 食材&quot;">​</a></h2><h3 id="配料" tabindex="-1">配料 <a class="header-anchor" href="#配料" aria-label="Permalink to &quot;配料&quot;">​</a></h3><table tabindex="0"><thead><tr><th>食材</th><th style="text-align:center;">份量</th><th>處理</th></tr></thead><tbody><tr><td>小黃瓜</td><td style="text-align:center;">2 條</td><td>切絲</td></tr><tr><td>榨菜或鹹菜疙瘩</td><td style="text-align:center;">少許</td><td>切末，提味用</td></tr><tr><td>蔥花</td><td style="text-align:center;">適量</td><td>從中間劃一刀再切，比較細</td></tr><tr><td>大蒜</td><td style="text-align:center;">適量</td><td>用搗的，不用剁或攪碎機</td></tr></tbody></table><h3 id="蒜汁醬" tabindex="-1">蒜汁醬 <a class="header-anchor" href="#蒜汁醬" aria-label="Permalink to &quot;蒜汁醬&quot;">​</a></h3><table tabindex="0"><thead><tr><th>食材</th><th style="text-align:center;">份量</th></tr></thead><tbody><tr><td>蒜泥</td><td style="text-align:center;">適量</td></tr><tr><td>冷開水</td><td style="text-align:center;">約半杯</td></tr><tr><td>醬油</td><td style="text-align:center;">1 大匙</td></tr><tr><td>胡椒</td><td style="text-align:center;">1/4 茶匙</td></tr><tr><td>糖</td><td style="text-align:center;">1/2 茶匙（提味，早期爺爺那輩不放糖）</td></tr><tr><td>味精</td><td style="text-align:center;">1/2 茶匙</td></tr><tr><td>醋（白醋）</td><td style="text-align:center;">1 大匙</td></tr><tr><td>麻油</td><td style="text-align:center;">1 匙</td></tr></tbody></table><blockquote><p>💡 這個醬汁也可以用來沾水餃</p></blockquote><h3 id="蛋皮" tabindex="-1">蛋皮 <a class="header-anchor" href="#蛋皮" aria-label="Permalink to &quot;蛋皮&quot;">​</a></h3><table tabindex="0"><thead><tr><th>食材</th><th style="text-align:center;">份量</th><th>備註</th></tr></thead><tbody><tr><td>雞蛋</td><td style="text-align:center;">2 顆</td><td></td></tr><tr><td>鹽</td><td style="text-align:center;">少許</td><td></td></tr><tr><td>料酒</td><td style="text-align:center;">1/2 茶匙</td><td>去腥</td></tr><tr><td>胡椒</td><td style="text-align:center;">少許</td><td></td></tr><tr><td>太白粉水</td><td style="text-align:center;">1/2 茶匙</td><td>讓蛋皮嫩滑 Q</td></tr></tbody></table><h3 id="芝麻醬-傳統做法-不放花生醬" tabindex="-1">芝麻醬（傳統做法，不放花生醬） <a class="header-anchor" href="#芝麻醬-傳統做法-不放花生醬" aria-label="Permalink to &quot;芝麻醬（傳統做法，不放花生醬）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>食材</th><th style="text-align:center;">份量</th></tr></thead><tbody><tr><td>芝麻醬</td><td style="text-align:center;">2 大匙</td></tr><tr><td>麻油</td><td style="text-align:center;">1 大匙</td></tr><tr><td>冷開水</td><td style="text-align:center;">適量（約 4 次半湯匙）</td></tr><tr><td>醬油</td><td style="text-align:center;">1/2 茶匙（調色）</td></tr></tbody></table><h3 id="花椒蔥油" tabindex="-1">花椒蔥油 <a class="header-anchor" href="#花椒蔥油" aria-label="Permalink to &quot;花椒蔥油&quot;">​</a></h3><table tabindex="0"><thead><tr><th>食材</th><th style="text-align:center;">份量</th></tr></thead><tbody><tr><td>蔥</td><td style="text-align:center;">適量</td></tr><tr><td>薑</td><td style="text-align:center;">4-5 片</td></tr><tr><td>油</td><td style="text-align:center;">1 杯</td></tr><tr><td>花椒</td><td style="text-align:center;">少許</td></tr></tbody></table><h3 id="麵條" tabindex="-1">麵條 <a class="header-anchor" href="#麵條" aria-label="Permalink to &quot;麵條&quot;">​</a></h3><table tabindex="0"><thead><tr><th>食材</th><th>備註</th></tr></thead><tbody><tr><td>鹼麵條</td><td>媽媽自己做有加鹼的（顏色較深），一般麵條亦可</td></tr></tbody></table><hr><h2 id="👨‍🍳-步驟" tabindex="-1">👨‍🍳 步驟 <a class="header-anchor" href="#👨‍🍳-步驟" aria-label="Permalink to &quot;👨‍🍳 步驟&quot;">​</a></h2><h3 id="_1-蒜汁醬" tabindex="-1">1. 蒜汁醬 <a class="header-anchor" href="#_1-蒜汁醬" aria-label="Permalink to &quot;1. 蒜汁醬&quot;">​</a></h3><ol><li>大蒜搗成泥</li><li>加約半杯冷開水</li><li>加入醬油、胡椒、糖、味精、醋、麻油</li><li>攪拌均勻</li></ol><h3 id="_2-蛋皮" tabindex="-1">2. 蛋皮 <a class="header-anchor" href="#_2-蛋皮" aria-label="Permalink to &quot;2. 蛋皮&quot;">​</a></h3><ol><li>2 顆蛋加鹽、料酒、胡椒、太白粉水</li><li>打散（不要打發）</li><li>不沾鍋噴少許油，<strong>中小火</strong></li><li>倒入蛋液，轉一轉讓蛋液均勻</li><li>約 <strong>10-20 秒</strong>翻面</li><li>煎到兩面黃黃的有<strong>焦香</strong>才香</li><li>切絲備用</li></ol><h3 id="_3-芝麻醬-傳統-不放花生醬" tabindex="-1">3. 芝麻醬（傳統，不放花生醬） <a class="header-anchor" href="#_3-芝麻醬-傳統-不放花生醬" aria-label="Permalink to &quot;3. 芝麻醬（傳統，不放花生醬）&quot;">​</a></h3><ol><li>2 大匙芝麻醬先用瓶裡的油（或麻油）打散</li><li><strong>一定要用冷開水慢慢加</strong>，一次半湯匙，邊加邊攪</li><li>加了水會先變稠，繼續加到流質狀態（約加 4 次）</li><li>最後加 1 大匙麻油、1/2 茶匙醬油調色</li></ol><h3 id="_4-花椒蔥油" tabindex="-1">4. 花椒蔥油 <a class="header-anchor" href="#_4-花椒蔥油" aria-label="Permalink to &quot;4. 花椒蔥油&quot;">​</a></h3><ol><li>蔥洗淨晾乾（或沖水瀝乾防炸鍋）</li><li>薑切薄片 4-5 片</li><li>一杯油<strong>中小火</strong>，先放薑片，再放蔥</li><li>炸到蔥變黃後放花椒 <strong>3-5 秒</strong>即撈出</li><li>💡 這個油可以拌涼菜、當明油，家裡常備</li></ol><h3 id="_5-煮麵" tabindex="-1">5. 煮麵 <a class="header-anchor" href="#_5-煮麵" aria-label="Permalink to &quot;5. 煮麵&quot;">​</a></h3><ol><li><strong>水要多</strong>，煮出來才清爽</li><li>煮到<strong>八九分熟</strong>，中間還有一點白芯即可</li><li>撈出瀝乾，倒<strong>蔥油拌勻</strong>防黏</li><li>用<strong>電風扇吹涼</strong>，不要過冷水（過冷水不好吃）</li></ol><h3 id="_6-組合" tabindex="-1">6. 組合 <a class="header-anchor" href="#_6-組合" aria-label="Permalink to &quot;6. 組合&quot;">​</a></h3><ol><li>先放<strong>醬汁</strong></li><li>再放<strong>蛋皮絲、小黃瓜絲、榨菜末、蔥花</strong></li><li>喜歡辣可加<strong>辣油</strong></li><li>醋不夠可以再加，更清爽</li></ol><hr><h2 id="🎯-主廚秘訣" tabindex="-1">🎯 主廚秘訣 <a class="header-anchor" href="#🎯-主廚秘訣" aria-label="Permalink to &quot;🎯 主廚秘訣&quot;">​</a></h2><ul><li>🔑 <strong>不放花生醬</strong> — 傳統眷村版純用芝麻醬</li><li>🔑 <strong>甜酒釀 + 花椒油</strong> — 關鍵靈魂，濃郁層次感</li><li>🔑 <strong>蒜用搗的</strong> — 不用剁或攪碎機，香氣不同</li><li>🔑 <strong>蛋皮煎到焦香</strong> — 兩面黃黃的才有香氣</li><li>🔑 <strong>芝麻醬慢慢加水</strong> — 一次半湯匙，邊加邊攪</li><li>🔑 <strong>花椒炸 3-5 秒即撈</strong> — 久了會苦</li><li>🔑 <strong>麵不要過冷水</strong> — 電風扇吹涼才好吃</li><li>🔑 <strong>水要多</strong> — 煮出來才清爽不黏</li></ul><hr><p><em>由 Hermes 於 2026/06/08 整理</em></p>',39)])])}const x=e(d,[["render",n]]);export{b as __pageData,x as default};
